    }
    auto conn = *conn_result;

    // Create the Product table
    auto table_result = sqlgen::create_table<Product>(conn);
    if (!table_result) {
      return false;
    }

    // Create indexes with IF NOT EXISTS logic
    using namespace sqlgen::literals;

    // Standard index on category
    auto idx_category = sqlgen::create_index<"idx_product_category", Product>("category"_c) | sqlgen::if_not_exists;
