```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = begin_transaction(conn);
  if (!begin_result) {
    return false;
  }

  try {
    // Read from account to check balance
    auto from_account_result = (read<std::vector<Account>> | where("account_id"_c == from_account_id))(conn);
    if (!from_account_result) {
      rollback(conn);
      return false;
    }

    auto from_account = from_account_result.value()[0];
    if (from_account.balance < amount) {
      rollback(conn);
      return false;
    }

    // Update from account (deduct amount)
    auto update_from_result = (update<Account>("balance"_c.set("balance"_c - amount)) | where("account_id"_c == from_account_id))(conn);
    if (!update_from_result) {
      rollback(conn);
      return false;
    }

    // Update to account (add amount)
    auto update_to_result = (update<Account>("balance"_c.set("balance"_c + amount)) | where("account_id"_c == to_account_id))(conn);
    if (!update_to_result) {
      rollback(conn);
      return false;
    }

    // Commit transaction
    auto commit_result = commit(conn);
    if (!commit_result) {
      rollback(conn);
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    rollback(conn);
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

