  }

  exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'A';").value();

  exec(conn, "ALTER TABLE Student ADD COLUMN Age INTEGER;").value();

  conn.and_then(sqlgen::drop<Major>).value();
