#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace left_join_explicit {

struct User {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> id;
  int user_id;
  std::string title;
};

/**
 * This function demonstrates a LEFT JOIN.
 * Returns: std::string.
 */
inline std::string left_join_explicit() {
  using namespace sqlgen::literals;

  // Create the query using sqlgen's fluent interface
  auto query = sqlgen::select_from<User, "t1">("id"_t1, "name"_t1, "posts.title"_t2)
             | sqlgen::left_join<Post, "t2">("id"_t1 == "user_id"_t2)
             | sqlgen::to<std::string>;

  // Convert the query to SQL string
  return sqlgen::sqlite::to_sql(query);
}

}  // namespace left_join_explicit
```

**Explanation of the implementation:**

1. **Namespace Usage**: `using namespace sqlgen::literals` enables the use of column literal syntax (`"id"_t1`).

2. **Query Construction**:
   - `sqlgen::select_from<User, "t1">("id"_t1, "name"_t1, "posts.title"_t2)` starts the query from the User table with alias "t1" and selects specific columns
   - `| sqlgen::left_join<Post, "t2">("id"_t1 == "user_id"_t2)` performs a LEFT JOIN with the Post table (alias "t2") using the join condition
   - `| sqlgen::to<std::string>` specifies the return type as string

3. **SQL Generation**: `sqlgen::sqlite::to_sql(query)` converts the constructed query object into a SQL string.

The generated SQL would be similar to:
```sql
SELECT t1.id, t1.name, posts.title FROM User AS t1 LEFT JOIN Post AS t2 ON t1.id = t2.user_id
```

This implementation follows sqlgen's principles of using operator overloading (`|`) for method chaining and template metaprogramming to build type-safe SQL queries at compile time.

